CREATE TRIGGER save_flight_preparation_history
AFTER INSERT, UPDATE, DELETE ON Flight_Preparation
FOR EACH ROW
BEGIN
  IF (NEW.id IS NOT NULL AND OLD.id IS NULL) OR (NEW.id IS NOT NULL AND OLD.id IS NOT NULL AND NEW.id <> OLD.id) THEN
    INSERT INTO Flight_Preparation_History (preparation_datetime, plane_id, technical_preparation, servicing_preparation, responsible_workers_id)
    VALUES (NEW.preparation_datetime, NEW.plane_id, NEW.technical_preparation, NEW.servicing_preparation, NEW.responsible_workers_id);
  ELSEIF (NEW.id IS NULL AND OLD.id IS NOT NULL) THEN
    INSERT INTO Flight_Preparation_History (preparation_datetime, plane_id, technical_preparation, servicing_preparation, responsible_workers_id)
    VALUES (OLD.preparation_datetime, OLD.plane_id, OLD.technical_preparation, OLD.servicing_preparation, OLD.responsible_workers_id);
  END IF;
END;

Вот триггер для MS SQL, который будет сохранять информацию о подготовке самолета к рейсу в отдельной таблице:

```
CREATE TRIGGER save_flight_preparation_history
ON Flight_Preparation
AFTER INSERT, UPDATE, DELETE
AS
BEGIN
  IF (NOT EXISTS(SELECT * FROM inserted)) RETURN;

  DECLARE @preparation_datetime DATETIME, @plane_id INT, @technical_preparation VARCHAR(50), @servicing_preparation VARCHAR(50), @responsible_workers_id INT;

  SELECT @preparation_datetime = preparation_datetime, @plane_id = plane_id, @technical_preparation = technical_preparation, @servicing_preparation = servicing_preparation, @responsible_workers_id = responsible_workers_id
  FROM inserted;

  IF (NOT EXISTS(SELECT * FROM deleted)) BEGIN
    INSERT INTO Flight_Preparation_History (preparation_datetime, plane_id, technical_preparation, servicing_preparation, responsible_workers_id)
    VALUES (@preparation_datetime, @plane_id, @technical_preparation, @servicing_preparation, @responsible_workers_id);
  END ELSE BEGIN
    IF (NOT EXISTS(SELECT * FROM inserted WHERE id = deleted.id)) BEGIN
      INSERT INTO Flight_Preparation_History (preparation_datetime, plane_id, technical_preparation, servicing_preparation, responsible_workers_id)
      VALUES (@preparation_datetime, @plane_id, @technical_preparation, @servicing_preparation, @responsible_workers_id);
    END;
  END;
END;
```

В этом триггере используется оператор `IF…ELSE`, чтобы определить, что именно изменилось в таблице `Flight_Preparation` (INSERT, UPDATE или DELETE). Затем полученные данные сохраняются в отдельной таблице `Flight_Preparation_History`.

Обратите внимание, что этот триггер не учитывает возможность одновременных изменений и не защищает от потенциальных проблем с блокировками данных. При необходимости можно дополнительно настроить блокировки или использовать другие методы сохранения истории изменений.
